from dataclasses import dataclass, field
from typing import Optional

@dataclass
class Reflection:
    step_id: str
    original_output: str
    score: float          # 0.0 – 1.0: quality of original_output
    flaws: list[str]      # specific problems found
    suggestions: list[str]  # how to fix each flaw
    revised_output: Optional[str] = None
    revised_score: Optional[float] = None
    iterations: int = 0

    @property
    def accepted(self) -> bool:
        """True if the final output meets the quality threshold."""
        final = self.revised_score if self.revised_score is not None else self.score
        return final >= 0.8

    @property
    def final_output(self) -> str:
        return self.revised_output if self.revised_output else self.original_output

REVISE_PROMPT = """Revise the following output based on the critique provided.

Objective: {objective}

Original output:
{original}

Critique:
  Score: {score:.2f}
  Flaws:
{flaws_text}
  Suggestions:
{suggestions_text}

Produce a revised output that addresses every flaw listed.
Do not add new content unrelated to the fixes.
"""

def revise(
    client: anthropic.Anthropic,
    reflection: Reflection,
    objective: str,
) -> str:
    flaws_text = "\n".join(f"    - {f}" for f in reflection.flaws)
    suggestions_text = "\n".join(f"    - {s}" for s in reflection.suggestions)
    prompt = REVISE_PROMPT.format(
        objective=objective,
        original=reflection.original_output,
        score=reflection.score,
        flaws_text=flaws_text,
        suggestions_text=suggestions_text,
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        messages=[{"role":"user","content":prompt}],
    )
    return resp.content[0].text.strip()

PLAN_REFLECT_PROMPT = """Reflect on the overall progress of an agent task.

Goal: {goal}
Success criteria:
{criteria}

Steps completed so far:
{history}

Remaining planned steps:
{remaining}

Answer these questions:
1. Is the completed work actually advancing the goal? Cite evidence.
2. Are the remaining steps still valid given what was learned?
3. Is there a faster or better path not currently in the plan?

Respond with JSON:
{{
  "on_track": bool,
  "concerns": ["concern 1", ...],
  "suggested_changes": ["change to the plan", ...],
  "confidence": float
}}
"""

def reflect_on_plan(
    client,
    goal: str,
    criteria: list[str],
    completed: list[dict],
    remaining: list[dict],
) -> dict:
    history_text = "\n".join(
        f"  {i+1}. {s['description']} → {str(s.get('result',''))[:120]}"
        for i, s in enumerate(completed)
    ) or "  (none)"
    remaining_text = "\n".join(
        f"  {i+1}. {s['description']}" for i, s in enumerate(remaining)
    ) or "  (none)"
    prompt = PLAN_REFLECT_PROMPT.format(
        goal=goal,
        criteria="\n".join(f"  - {c}" for c in criteria),
        history=history_text,
        remaining=remaining_text,
    )
    import anthropic, json, re
    client_a = client
    resp = client_a.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role":"user","content":prompt}],
    )
    raw = resp.content[0].text
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    return json.loads(m.group()) if m else {"on_track": True, "concerns": []}

from collections import Counter

class ReflectionMemory:
    def __init__(self):
        self.reflections: list[Reflection] = []

    def record(self, reflection: Reflection) -> None:
        self.reflections.append(reflection)

    def average_score(self) -> float:
        scores = [r.revised_score or r.score for r in self.reflections]
        return sum(scores) / len(scores) if scores else 1.0

    def common_flaws(self, top_n: int = 3) -> list[str]:
        all_flaws = [f for r in self.reflections for f in r.flaws]
        counter = Counter(all_flaws)
        return [flaw for flaw, _ in counter.most_common(top_n)]

    def standing_reminders(self) -> str:
        flaws = self.common_flaws()
        if not flaws:
            return ""
        lines = ["Known recurring issues to avoid:"]
        for f in flaws:
            lines.append(f"  - {f}")
        return "\n".join(lines)


